#include <iostream>

class SimpleCounter {
private:
    int count = 0; // Modern C++ in-class initialization

public:
    // 'this->count' resolves ambiguity between parameter and member variable
    void setCount(int count) {
        this->count = count;
    }

    void increment() {
        this->count++; // Implicitly same as count++
    }

    [[nodiscard]] int getCount() const {
        return this->count;
    }
};

int main() {
    SimpleCounter counter;
    counter.setCount(10);
    counter.increment();
    std::cout << "Final count: " << counter.getCount() << std::endl;
    return 0;
}

code_example_2_practical.code:
#include <iostream>
#include <string_view>
#include <cstdint>

class PacketHeader {
private:
    uint16_t sourcePort_ = 0;
    uint16_t destPort_ = 0;
    uint32_t sequenceNum_ = 0;
    bool isSyn_ = false;

public:
    // Setter returning a reference to the current object (*this) to enable chaining
    PacketHeader& setSourcePort(uint16_t port) {
        this->sourcePort_ = port;
        return *this;
    }

    PacketHeader& setDestPort(uint16_t port) {
        this->destPort_ = port;
        return *this;
    }

    PacketHeader& setSequenceNum(uint32_t seq) {
        this->sequenceNum_ = seq;
        return *this;
    }

    PacketHeader& setSynFlag(bool syn) {
        this->isSyn_ = syn;
        return *this;
    }

    void print() const {
        std::cout << "Packet [Src: " << sourcePort_ 
                  << ", Dst: " << destPort_ 
                  << ", Seq: " << sequenceNum_ 
                  << ", SYN: " << (isSyn_ ? "Yes" : "No") << "]" << std::endl;
    }
};

int main() {
    PacketHeader tcpHeader;

    // Method Chaining made possible by returning reference to *this
    tcpHeader.setSourcePort(443)
             .setDestPort(51020)
             .setSequenceNum(100502)
             .setSynFlag(true);

    tcpHeader.print();
    return 0;
}

